/* pace.min.js - thin shim that shows a tiny top-of-page bar during navigation */
(function () {
    if (window.Pace) return;
    var bar = document.createElement('div');
    bar.className = 'pace';
    bar.innerHTML = '<div class="pace-progress" style="transform: translateX(0%);"></div>';
    document.addEventListener('DOMContentLoaded', function () {
        document.body.appendChild(bar);
        bar.classList.add('pace-inactive');
    });
    window.addEventListener('beforeunload', function () {
        bar.classList.remove('pace-inactive');
        var p = bar.querySelector('.pace-progress');
        if (p) p.style.transform = 'translateX(80%)';
    });
    window.Pace = { start: function(){}, stop: function(){} };
})();
